const express = require('express');
const { Pool } = require('pg');
const cors = require('cors');

const app = express();
app.use(cors());
app.use(express.json());

const pool = new Pool({
  user: 'postgres', // your username
  host: 'localhost',
  database: 'ticket_db',
  password: 'your_password',
  port: 5432,
});

// CREATE: Purchase a ticket
app.post('/tickets', async (req, res) => {
  const { event_name, price, buyer_name } = req.body;
  try {
    const result = await pool.query(
      'INSERT INTO tickets (event_name, price, buyer_name) VALUES ($1, $2, $3) RETURNING *',
      [event_name, price, buyer_name]
    );
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

// READ: Get all tickets
app.get('/tickets', async (req, res) => {
  try {
    const result = await pool.query('SELECT * FROM tickets');
    res.json(result.rows);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

// DELETE: Cancel a ticket
app.delete('/tickets/:id', async (req, res) => {
  try {
    await pool.query('DELETE FROM tickets WHERE id = $1', [req.params.id]);
    res.json({ message: "Ticket deleted" });
  } catch (err) {
    res.status(500).send(err.message);
  }
});

app.listen(5000, () => console.log('Server running on port 5000'));

// UPDATE: Edit ticket details
app.put('/tickets/:id', async (req, res) => {
  const { id } = req.params;
  const { event_name, price, buyer_name } = req.body;
  try {
    const result = await pool.query(
      'UPDATE tickets SET event_name = $1, price = $2, buyer_name = $3 WHERE id = $4 RETURNING *',
      [event_name, price, buyer_name, id]
    );
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).send(err.message);
  }
});